import{_ as e,o,c as d,ag as r}from"./chunks/framework.HG0H2VLS.js";const m=JSON.parse('{"title":"CCTopNavigation — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/patterns/TopNavigation/TopNavigation.figma-notes.md","filePath":"public/demos/src/cc/patterns/TopNavigation/TopNavigation.figma-notes.md"}'),a={name:"public/demos/src/cc/patterns/TopNavigation/TopNavigation.figma-notes.md"};function i(n,t,c,s,l,p){return o(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="cctopnavigation-—-figma-notes" tabindex="-1">CCTopNavigation — Figma Notes <a class="header-anchor" href="#cctopnavigation-—-figma-notes" aria-label="Permalink to &quot;CCTopNavigation — Figma Notes&quot;">​</a></h1><p><strong>Figma file:</strong> <a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System?node-id=4099-3634" target="_blank" rel="noreferrer"><code>ETKqleZdpertwFEo40YB5n</code></a> (CC Hybrid Design System) <strong>Tier:</strong> Pattern <strong>Component set node:</strong> <code>4099:3634</code> (frame name <code>CCTopNavigation</code>) <strong>Files:</strong> <code>CCTopNavigation.css</code>, <code>CCTopNavigation.html</code>, <code>CCTopNavigation.figma.ts</code>, <code>CCTopNavigation.figma-notes.md</code></p><hr><h2 id="variant-matrix-verified-from-figma-get-metadata-2026-05-15" tabindex="-1">Variant matrix (verified from Figma <code>get_metadata</code> 2026-05-15) <a class="header-anchor" href="#variant-matrix-verified-from-figma-get-metadata-2026-05-15" aria-label="Permalink to &quot;Variant matrix (verified from Figma `get_metadata` 2026-05-15)&quot;">​</a></h2><p>Two axes: <strong>Type</strong> × <strong>Device</strong> = 4 variants.</p><table tabindex="0"><thead><tr><th>Node ID</th><th>Device</th><th>Type</th><th>Width</th><th>Description</th></tr></thead><tbody><tr><td><code>4099:3631</code></td><td>Desktop</td><td>Default</td><td>1280</td><td>&quot;Zone name &gt; Level 1&quot;</td></tr><tr><td><code>4099:3633</code></td><td>Desktop</td><td>Multizone</td><td>1280</td><td>&quot;Zone Selector ▾ &gt; Level 1 &gt; Level 2&quot;</td></tr><tr><td><code>4099:3632</code></td><td>Mobile</td><td>Default</td><td>390</td><td>&quot;Zone name &gt; Level 1&quot;, avatar-only user</td></tr><tr><td><code>4099:3630</code></td><td>Mobile</td><td>Multizone</td><td>390</td><td>&quot;Zone Selector ▾ &gt; Level 1&quot;, avatar-only user</td></tr></tbody></table><p>Mobile responsiveness handled via <code>@container (max-width: 767px)</code> (the bar is a <code>container-type: inline-size</code> context) — single HTML structure collapses to the mobile layout. No <code>--mobile</code> modifier class.</p><p><strong>Breadcrumb item budget:</strong> max <strong>2 items</strong> below MD (768px), <strong>3 items</strong> at ≥768px. The breadcrumb keeps the zone selector + 1 level (or 2 levels when there&#39;s no zone selector). Any trailing crumb beyond that budget carries <code>breadcrumb__item--collapse</code> (and its leading separator <code>breadcrumb__separator--collapse</code>); the <code>@container (max-width: 767px)</code> block hides them, and the crumb that becomes last is promoted to the current-page colour. So Multizone renders &quot;Zone Selector &gt; Level 1 &gt; Level 2&quot; at ≥768px and collapses to &quot;Zone Selector &gt; Level 1&quot; below it (Figma 4099:3630). The 2-item Default variant carries no <code>--collapse</code> markers, so it is unaffected.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper (<code>CCTopNavigation</code>)</td><td><code>.cc-top-navigation</code> (<code>&lt;header&gt;</code>)</td></tr><tr><td><code>Breadcrumb</code></td><td>Composes existing <code>.breadcrumb</code> (see <code>src/components/Breadcrumb/</code>)</td></tr><tr><td><code>Top Nav Actions</code></td><td><code>.cc-top-navigation__actions</code></td></tr><tr><td><code>User</code> block</td><td><code>.cc-top-navigation__user</code></td></tr><tr><td>Portrait (ellipse4)</td><td><code>.portrait</code> (existing Portraits component)</td></tr><tr><td>Username text</td><td><code>.cc-top-navigation__user-name</code></td></tr><tr><td>Chevron-down on user</td><td><code>.cc-top-navigation__user-chevron</code></td></tr><tr><td><code>Desktop</code> (monitor icon)</td><td><code>.cc-top-navigation__preview</code></td></tr></tbody></table><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="wrapper" tabindex="-1">Wrapper <a class="header-anchor" href="#wrapper" aria-label="Permalink to &quot;Wrapper&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Background</td><td><code>var(--cc-header-primary-bg)</code> (#0f3b53 in CC light)</td></tr><tr><td>Min height</td><td><code>var(--ai-spacing-9)</code> (48px)</td></tr><tr><td>Padding (x)</td><td><code>var(--ai-spacing-5)</code> (16px)</td></tr><tr><td>Gap</td><td><code>var(--ai-spacing-5)</code> (16px)</td></tr></tbody></table><h3 id="breadcrumb-contextual-override-—-dark-bg" tabindex="-1">Breadcrumb (contextual override — dark bg) <a class="header-anchor" href="#breadcrumb-contextual-override-—-dark-bg" aria-label="Permalink to &quot;Breadcrumb (contextual override — dark bg)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Element</th><th>Token</th><th>Notes</th></tr></thead><tbody><tr><td><code>.breadcrumb__link</code></td><td><code>var(--ai-text-invert-secondary)</code></td><td>Inverted from default <code>--ai-text-secondary</code></td></tr><tr><td><code>.breadcrumb__link:hover</code></td><td><code>var(--ai-text-invert)</code></td><td>Inverted from default <code>--ai-text-primary</code></td></tr><tr><td><code>.breadcrumb__dropdown</code></td><td><code>var(--ai-text-invert-secondary)</code></td><td>Same as link</td></tr><tr><td><code>.breadcrumb__dropdown:hover</code></td><td><code>var(--ai-text-invert)</code></td><td></td></tr><tr><td><code>.breadcrumb__item--current</code></td><td><code>var(--ai-text-invert)</code></td><td>Inverted from default <code>--ai-text-primary</code></td></tr><tr><td><code>.breadcrumb__separator</code></td><td><code>var(--ai-icon-invert-secondary)</code></td><td>Inverted from default <code>--ai-icon-contrast</code></td></tr></tbody></table><p>Case B contextual override per CLAUDE.md — scoped to <code>.cc-top-navigation .breadcrumb__*</code>, does not modify the Breadcrumb component itself.</p><h3 id="user-block" tabindex="-1">User block <a class="header-anchor" href="#user-block" aria-label="Permalink to &quot;User block&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Notes</th></tr></thead><tbody><tr><td>Gap</td><td><code>var(--ai-spacing-3)</code> (8px)</td><td>Between portrait and name</td></tr><tr><td>Portrait size</td><td><code>var(--ai-spacing-7)</code> (32px)</td><td><strong>Figma uses 28px</strong> — see Token gaps</td></tr><tr><td>Username font-family</td><td><code>var(--ai-font-title)</code></td><td>Inter</td></tr><tr><td>Username font-weight</td><td><code>var(--ai-font-medium)</code> (500)</td><td></td></tr><tr><td>Username font-size</td><td><code>var(--ai-font-fixed-xs)</code> (14px)</td><td></td></tr><tr><td>Username colour</td><td><code>var(--ai-text-invert-secondary)</code></td><td></td></tr><tr><td>Username letter-spacing</td><td><code>0.28px</code></td><td>Optical — letter-spacing is a documented px exception</td></tr><tr><td>Username font-feature-settings</td><td><code>&#39;salt&#39; 1</code></td><td>Inter stylistic alternates</td></tr><tr><td>User chevron wrapper</td><td><code>var(--ai-icon-size-lg)</code> (24px)</td><td>Click-target padding</td></tr><tr><td>User chevron icon</td><td><code>var(--ai-icon-size-sm)</code> (16px)</td><td></td></tr><tr><td>User chevron colour</td><td><code>var(--ai-icon-invert-secondary)</code></td><td></td></tr></tbody></table><h3 id="preview-button-monitor-icon" tabindex="-1">Preview button (monitor icon) <a class="header-anchor" href="#preview-button-monitor-icon" aria-label="Permalink to &quot;Preview button (monitor icon)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Size</td><td><code>var(--ai-icon-size-md)</code> (20px)</td></tr><tr><td>Background</td><td><code>transparent</code></td></tr><tr><td>Border</td><td>none</td></tr><tr><td>Icon size</td><td><code>var(--ai-icon-size-md)</code> (20px)</td></tr><tr><td>Icon colour</td><td><code>var(--cc-header-icon)</code></td></tr><tr><td>Icon colour (hover)</td><td><code>var(--ai-text-invert)</code></td></tr><tr><td>Transition</td><td><code>color var(--ai-transition-default)</code></td></tr></tbody></table><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gap</th><th>Figma value</th><th>Resolution</th></tr></thead><tbody><tr><td>User portrait size</td><td>28px</td><td>Approved: use <code>var(--ai-spacing-7)</code> (32px) — closest existing token. 4px larger than Figma.</td></tr><tr><td>Mobile container gap</td><td>18px (Figma <code>--size-4-5</code>)</td><td>Approved: use <code>var(--ai-spacing-5)</code> (16px) for both desktop and mobile — token-clean and consistent. 2px deviation from Figma on mobile.</td></tr></tbody></table><hr><h2 id="interactions" tabindex="-1">Interactions <a class="header-anchor" href="#interactions" aria-label="Permalink to &quot;Interactions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Behaviour</th><th>Status</th></tr></thead><tbody><tr><td>Zone Selector dropdown (Multizone)</td><td>Composes existing <code>Dropdown</code> component (<code>.dropdown</code> + <code>.dropdown__trigger</code> + <code>.dropdown__panel</code>). <code>Dropdown.js</code> auto-init handles open/close/click-outside/Escape.</td><td><strong>Wired</strong></td></tr><tr><td>User block (portrait + name + chevron)</td><td>Rendered as <code>&lt;button&gt;</code> with <code>aria-haspopup=&quot;true&quot;</code> and <code>aria-label=&quot;User menu&quot;</code> but the click handler is intentionally <strong>not wired</strong>. Per user direction: build visual chrome only, leave interaction TODO.</td><td><strong>Visual only</strong></td></tr><tr><td>Preview button (monitor icon)</td><td>Rendered as <code>&lt;button aria-label=&quot;Preview as desktop&quot;&gt;</code> for accessibility. Click handler is <strong>not wired</strong> — purpose pending designer confirmation.</td><td><strong>Visual only</strong></td></tr></tbody></table><hr><h2 id="responsive-behaviour" tabindex="-1">Responsive behaviour <a class="header-anchor" href="#responsive-behaviour" aria-label="Permalink to &quot;Responsive behaviour&quot;">​</a></h2><p><code>@media (max-width: 767px)</code>:</p><ul><li><code>.cc-top-navigation__user-name</code> → <code>display: none</code></li><li><code>.cc-top-navigation__user-chevron</code> → <code>display: none</code></li></ul><p>Result: mobile shows only the portrait in the User block. Preview button stays visible.</p><hr><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><strong>Breadcrumb</strong> (<code>src/components/Breadcrumb/</code>) — supplies the breadcrumb list / link / dropdown trigger CSS. CCTopNavigation supplies a contextual colour override only.</li><li><strong>Dropdown</strong> (<code>src/components/Dropdown/</code>) — required for Multizone (Zone Selector dropdown). Include both <code>Dropdown.css</code> and <code>Dropdown.js</code> on pages using this pattern.</li><li><strong>Portraits</strong> (<code>src/components/Portraits/</code>) — supplies the <code>.portrait</code> class for the user image.</li><li><strong>Lucide</strong> icons — <code>chevron-right</code> (breadcrumb separator), <code>chevron-down</code> (user chevron + breadcrumb dropdown chevron), <code>monitor</code> (preview button).</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-15: Initial pattern scaffold. Built from Figma component set <code>4099:3634</code> (CC Hybrid Design System). 4 variants (Default × Desktop, Multizone × Desktop, Default × Mobile, Multizone × Mobile) reduced to a single responsive HTML structure with <code>@media (max-width: 767px)</code> for mobile collapses. Token gaps documented: 28px portrait → 32px, 18px mobile gap → 16px. Contextual override scoped to <code>.cc-top-navigation .breadcrumb__*</code> for invert colours on the dark navy bg.</li></ul>',39)])])}const u=e(a,[["render",i]]);export{m as __pageData,u as default};
